37a870cc  	 *  pusher to capture the line for assertion. */
9f22bdb7  	stderr?: (line: string) => void;
d10b36aa  }
e3b0c442  
8d64a30d  /**
521cfc03   * Runs the boot-time audit (pure, no side effects beyond the stderr callback)
5f38696c   * and returns the OfflineAuditResult. session.ts calls this right after
b72d3b00   * tool registration to:
a7bbdfb3   *   - Print the [emmy] OFFLINE OK / NETWORK USED banner to stderr
03208703   *   - Feed the result into setInitialAudit + emitEvent("session.offline_audit.complete")
64e75266   *
436171dd   * Color is applied inline to the stderr line (matches renderBadge color scheme).
64e75266   *
64ead4e8   * Plan 03.1-02: the boot banner still renders green (OFFLINE OK) because the
a74b9ea3   * boot-time audit doesn't know whether SearxNG is up — the yellow transition
ee13a6c0   * happens lazily on first successful web_search call (session.ts wires the
93a61dcd   * flipToYellow callback into webSearch's onSuccess path).
533a9f11   */
82cb3993  export function runBootOfflineAudit(opts: RunBootAuditOpts): OfflineAuditResult {
7406be33  	const rawResult = auditToolRegistry(opts.toolRegistrations, opts.allowlist);
3c90c034  	// D-36: boot-time audit's red path remains "legacy red" (NETWORK USED with
6a96c867  	// tool→host diagnostic). Only green results get badge_state:"green" stamped
1f415110  	// explicitly so the 3-state renderer picks the OFFLINE OK path verbatim.
a1d5f9d3  	// Red audits here are tool-registration-time violations (config-detected,
88788170  	// not runtime); the D-36 reserved red state (badge_state:"red") is for
191b8b03  	// actual non-loopback inference detection, which today never fires.
93358feb  	const result: OfflineAuditResult = rawResult.offline_ok
635bb06e  		? { ...rawResult, badge_state: "green" }
ac8fa348  		: rawResult;
1211fa00  	const sink = opts.stderr ?? ((line: string) => process.stderr.write(`${line}\n`));
0025cf88  	const color = result.offline_ok ? GREEN : RED;
6a12754b  	sink(`${color}[emmy] ${renderBadgePlain(result)}${RESET}`);
740e1409  	return result;
d10b36aa  }
