20d385f5   * assertions are not polluted by prior test runs.
533a9f11   */
e506d6c5  export function __resetBadgeStateForTests(): void {
aef270da  	_lastResult = {
b4f09011  		offline_ok: true,
cc2cd110  		violating_tool: null,
3a127ae6  		violating_host: null,
56e6fb4f  		badge_state: "green",
d5130ff6  	};
e2f75489  	_ctx = null;
d10b36aa  }
e3b0c442  
8d64a30d  /**
