b10d76e2   * import this — read from a bound ctx instead.
533a9f11   */
766a2bfc  export function getBadgeStateForTests(): OfflineAuditResult | null {
eb2dbd94  	return _lastResult;
d10b36aa  }
e3b0c442  
93853c41  // --- Boot audit helper ---------------------------------------------------
e3b0c442  
91072943  export interface RunBootAuditOpts {
