b9be8304  			if (opts.onSuccess) {
bbe3f2c2  				try {
ca416cab  					opts.onSuccess(results);
1d0a3a50  				} catch {
d4380765  					/* never let the success-hook mask a returned result */
0812d29f  				}
4ffaefcc  			}
392b2fa4  			return { results };
b7fa8888  		},
d5130ff6  	};
