1f415110  	// explicitly so the 3-state renderer picks the OFFLINE OK path verbatim.
a1d5f9d3  	// Red audits here are tool-registration-time violations (config-detected,
88788170  	// not runtime); the D-36 reserved red state (badge_state:"red") is for
191b8b03  	// actual non-loopback inference detection, which today never fires.
93358feb  	const result: OfflineAuditResult = rawResult.offline_ok
635bb06e  		? { ...rawResult, badge_state: "green" }
ac8fa348  		: rawResult;
1211fa00  	const sink = opts.stderr ?? ((line: string) => process.stderr.write(`${line}\n`));
0025cf88  	const color = result.offline_ok ? GREEN : RED;
6a12754b  	sink(`${color}[emmy] ${renderBadgePlain(result)}${RESET}`);
740e1409  	return result;
d10b36aa  }
