b51541ad  export interface EnforcementContext {
493a0845  	/** Hostname-exact allowlist. Empty → default-deny (web_fetch itself flips red). */
9f6db24c  	allowlist: readonly string[];
eb8b6169  	/** Profile ref stamped onto the violation event for provenance. */
d68995b0  	profileRef: { id: string; version: string; hash: string };
4fd66a1d  	/** Optional callback fired when a violation is detected (session.ts wires
