820626d9  	// malformed input); re-parse here for the authoritative hostname used
cbbb6fe0  	// in the event + error message.
67f35889  	const hostname = new URL(url).hostname;
81f38bfc  	emitEvent({
4d12bc80  		event: "tool.web_fetch.violation",
01ecdf58  		ts: new Date().toISOString(),
5a4d6af6  		profile: ctx.profileRef,
f6cdd6c2  		url,
fbed48e0  		hostname,
eeb33785  	});
d4a63a91  	if (ctx.onViolation) {
131bbee0  		try {
5658352b  			ctx.onViolation({ url, hostname });
06518044  		} catch {
8344334b  			// Never let the UX callback mask the original violation; the
e3e36e08  			// error thrown below is the authoritative signal to the caller.
3713bbfd  		}
a32a3bb7  	}
34ebbae0  	throw new WebFetchAllowlistError(url, hostname);
d10b36aa  }
